import sys


def main():
    input = sys.stdin.readline
    n = int(input())
    a = list(map(int, input().split()))
    b = list(map(int, input().split()))
    c = [0] * 5
    for i in range(n):
        c[a[i] - 1] += 1
        c[b[i] - 1] -= 1
    ans = 0
    for i in range(5):
        if c[i] != 0:
            return -1
    for i in range(n):
        if a[i] != b[i]:
            ans += 1
    return ans // 2


if __name__ == '__main__':
    print(main())
